{
  "mode": "io",
  "tests": [
    {
      "name": "button_not_overlapping",
      "input": "Check if the Back to Home button overlaps with the footer.",
      "output": "false",
      "notes": "Validates that the button does not overlap with the grey background footer."
    },
    {
      "name": "button_visible_on_load",
      "input": "Load the page and check if the Back to Home button is visible.",
      "output": "true",
      "notes": "Ensures that the button is visible upon loading the page."
    },
    {
      "name": "footer_background_color",
      "input": "Get the footer background color.",
      "output": "#f0f0f0",
      "notes": "Checks that the footer has the correct grey background color."
    },
    {
      "name": "button_positioning",
      "input": "Get the position of the Back to Home button.",
      "output": "{\"top\": \"80%\", \"left\": \"50%\"}",
      "notes": "Validates that the button is positioned correctly on the page."
    },
    {
      "name": "button_click_functionality",
      "input": "Simulate a click on the Back to Home button.",
      "output": "redirect to home",
      "notes": "Ensures that clicking the button redirects the user to the home page."
    },
    {
      "name": "responsive_design_check",
      "input": "Resize the window to mobile dimensions.",
      "output": "true",
      "notes": "Validates that the button remains functional and visible on mobile devices."
    },
    {
      "name": "button_disabled_state",
      "input": "Check if the button is disabled under certain conditions.",
      "output": "false",
      "notes": "Ensures that the button is not disabled when it should be active."
    },
    {
      "name": "footer_height_check",
      "input": "Get the height of the footer.",
      "output": "60px",
      "notes": "Validates that the footer height does not interfere with the button's position."
    }
  ],
  "assumptions": "The page layout and styles are correctly implemented as per the design assets.",
  "notes": "Ensure to test on various screen sizes to validate responsiveness."
}
